with company as (
), workplaces_seed(id,name,address) as (values ('00000000-0000-0000-0000-000000000101'::uuid,'本社','東京都千代田区丸の内1-1-1'),('00000000-0000-0000-0000-000000000102'::uuid,'茨城営業所','茨城県水戸市中央1-1-1'))



select '00000000-0000-0000-0000-000000000001', p.id, s.id,
case when (row_number() over (partition by p.id order by s.name) + extract(day from p.work_date)::int) % 7 = 0 then 'unavailable'::availability_status when (row_number() over (partition by p.id order by s.name) + extract(day from p.work_date)::int) % 4 = 0 then 'conditional'::availability_status else 'available'::availability_status end,
case when (row_number() over (partition by p.id order by s.name) + extract(day from p.work_date)::int) % 4 = 0 then '時間相談可' else '' end
from projects p cross join profiles s where s.role='staff' on conflict (project_id, staff_id) do update set status=excluded.status, note=excluded.note;
